function [acf,imp] = partoacf(phi,theta,lagmax,var_a)%partoacf%%  This routine takes the parameters of an%  ARMA model and computes the autocorrelation%  function of the process.  The ARMA parameters%  should be given in the vectors phi (AR) and%  theta (MA).  The routine assumes that the%  variance of the white noise is var_a.%  The number of acf elements to be computed will%  be equal to lagmax.  The first elements of %  phi and theta are typically equal to 1, which%  corresponds to the zeroth order term.%  The form of phi is [1 phi1 phi2], and the%  form of theta is [1 theta1 theta2], where%   y(t) + phi1*y(t-1) + phi2*y(t-2) = a(t) + theta1*a(t-1) + theta2*a(t-2)%p=length(phi);[n,m]=size(phi);if m==p  phi=phi';endq=length(theta);[n,m]=size(theta);if m==q  theta=theta';endif p>q,  theta=[theta;zeros((p-q),1)];endif p<q,  phi=[phi;zeros((q-p),1)];  p=q;enda1=phi;for i=2:(p),  a1=[a1 [phi(i:p);zeros((i-1),1)] ];enda1(:,1)=a1(:,1)/2;a2=phi;for i=2:p,  a2=[a2 [zeros((i-1),1);phi(1:(p+1-i))] ];endimp=a2\theta;b1=theta;for i=2:p,  b1=[b1 [theta(i:p);zeros((i-1),1)] ];enda2(:,1)=a2(:,1)/2;acf=(a1+a2)\b1*imp;mtot=length(acf);for i=(mtot):lagmax-1,  tacf=-phi(2:p)'*acf(i:-1:i-p+2);  acf=[acf;tacf];endacf=var_a*acf;